# ER Diagram Notation - Basic Component Definition
# For BSc Physical Science (CS) - Delhi University

# Define entities as dictionaries with their attributes
entities = {
    "Student": {
        "attributes": ["student_id (PK)", "name", "email", "phone", "enrollment_date"],
        "entity_type": "Strong"
    },
    "Course": {
        "attributes": ["course_id (PK)", "course_name", "credits", "department"],
        "entity_type": "Strong"
    },
    "Enrollment": {
        "attributes": ["enrollment_id (PK)", "grade", "semester"],
        "entity_type": "Weak"  # Weak entity - depends on Student and Course
    }
}

# Define relationships
relationships = [
    {
        "name": "enrolls_in",
        "participating_entities": ["Student", "Course"],
        "cardinality": "Many-to-Many",  # M:N
        "structural_constraints": "(min, max) = (1, n)"
    },
    {
        "name": "has",
        "participating_entities": ["Student", "Enrollment"],
        "cardinality": "One-to-Many",  # 1:N
        "structural_constraints": "(min, max) = (1, 1)"
    }
]

# Display ER components
print("=" * 60)
print("ER DIAGRAM NOTATION - COMPONENT REPRESENTATION")
print("=" * 60)

print("\n📦 ENTITIES:")
for entity, details in entities.items():
    print(f"\n  ◆ {entity} ({details['entity_type']} Entity)")
    print(f"    Attributes: {', '.join(details['attributes'])}")

print("\n\n🔗 RELATIONSHIPS:")
for rel in relationships:
    print(f"\n  ◇ {rel['name']}")
    print(f"    Entities: {' -- '.join(rel['participating_entities'])}")
    print(f"    Cardinality: {rel['cardinality']}")
    print(f"    Constraints: {rel['structural_constraints']}")
